import pandas as pd
from scipy.io import loadmat
from src.paths import ROOT
import numpy as np

exp_data = loadmat(ROOT / 'data/images/nsd_expdesign.mat', simplify_cells=True)
from_nsdid_to_sharedid = {str(nsdid.item()): str(sharedid+1) for sharedid, nsdid in enumerate(exp_data['sharedix'])}

df = pd.read_csv(ROOT / "data/images/nsd_stim_info_merged.csv")
red_df = df.loc[df.shared1000==True,['cocoId', 'nsdId']]
from_nsd_to_coco = {nsd+1: coco for nsd, coco in zip(red_df.nsdId, red_df.cocoId)} # correcting for indexing mismatch

def get_image_path(nsd_index: str):

    image_path = f"data/images/stimuli/shared{pad_shared_id(from_nsdid_to_sharedid[nsd_index])}_nsd{pad_nsd_id(nsd_index)}.png"
    return image_path

def pad_session_id(session_index):

    str_ind = str(session_index)
    len_pad_needed = 2 - len(str_ind)
    padded_idx = f"{'0'*len_pad_needed}{str_ind}"

    return padded_idx

def pad_nsd_id(session_index):

    str_ind = str(session_index)
    len_pad_needed = 5 - len(str_ind)
    padded_idx = f"{'0'*len_pad_needed}{str_ind}"

    return padded_idx

def pad_shared_id(index):

    str_ind = str(index)
    len_pad_needed = 4 - len(str_ind)
    padded_idx = f"{'0'*len_pad_needed}{str_ind}"

    return padded_idx

